+async fn timed_async_value<T, F, Fut>(f: F) -> TimedValue<T>
+where
+    F: FnOnce() -> Fut,
+    Fut: std::future::Future<Output = T>,
+{
+    let start = Instant::now();
+    let value = f().await;
+    TimedValue {
+        value,
+        duration_ms: start.elapsed().as_millis() as u64,
+    }
+}
